#!/usr/bin/env node
// Regenerates site/lib/generated-types.ts from schema/*.schema.json.
// Wired into prebuild so the file stays fresh on every dev/build cycle.
//
// site/lib/types.ts remains the consumer-facing facade (it carries the
// enriched/computed types that aren't in any single schema). When you add a
// new schema field, cross-check the freshly regenerated file below.

import { compileFromFile } from "json-schema-to-typescript";
import { writeFileSync } from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const here = path.dirname(fileURLToPath(import.meta.url));
const schemaDir = path.resolve(here, "..", "..", "schema");
const outPath = path.resolve(here, "..", "lib", "generated-types.ts");

const schemas = [
  { file: "card.schema.json", banner: "card" },
  { file: "issuer.schema.json", banner: "issuer" },
  { file: "network.schema.json", banner: "network" },
  { file: "loyalty_program.schema.json", banner: "loyalty_program" },
];

let out = "/* eslint-disable */\n";
out += "// Auto-generated from schema/*.schema.json — do not edit by hand.\n";
out += "// Regenerated by site/scripts/gen-types.mjs (runs in prebuild).\n\n";

for (const { file, banner } of schemas) {
  const schemaPath = path.join(schemaDir, file);
  try {
    const ts = await compileFromFile(schemaPath, {
      bannerComment: `// ─── ${banner} (from ${file}) ─────────────────────────────────\n`,
      style: { semi: true, singleQuote: false },
    });
    out += ts + "\n";
  } catch (err) {
    if (err && err.code === "ENOENT") continue;
    throw err;
  }
}

writeFileSync(outPath, out, "utf8");
console.log(`Wrote ${outPath}`);
